using System;
using System.DirectoryServices;

namespace MyApp
{
    public class Authenticator
    {
        public bool Authenticate(string username, string password)
        {
            // Construct the LDAP query to find the user
            string ldapQuery = "(&(objectClass=user)(sAMAccountName=" + username + "))";

            // Create an instance of DirectoryEntry to represent the Active Directory
            DirectoryEntry directoryEntry = new DirectoryEntry("LDAP://example.com", username, password);

            // Bind to the directory entry with the LDAP query
            directoryEntry.Bind(ldapQuery);

